    24	void
    25	opt(llvm::Module& mod)
    26	{
    27	  using namespace llvm;
    28	
    29	  // 定义分析pass的管理器
    30	  LoopAnalysisManager lam;
    31	  FunctionAnalysisManager fam;
    32	  CGSCCAnalysisManager cgam;
    33	  ModuleAnalysisManager mam;
    34	  ModulePassManager mpm;
    35	
    36	  // 注册分析pass的管理器
    37	  PassBuilder pb;
    38	  pb.registerModuleAnalyses(mam);
    39	  pb.registerCGSCCAnalyses(cgam);
    40	  pb.registerFunctionAnalyses(fam);
    41	  pb.registerLoopAnalyses(lam);
    42	  pb.crossRegisterProxies(lam, fam, cgam, mam);
    43	
    44	  // 添加分析pass到管理器中
    45	  mam.registerPass([]() { return StaticCallCounter(); });
    46	
    47	#ifdef TASK4_LLM
    48	
    49	  // 使用 LLM 技术来辅助编译优化
    50	  // 初始化 Python 解释器
    51	  Py::scoped_interpreter guard{};
    52	  // import sys 库，添加 TASK4_DIR 到寻找 Python 库的 path 中
    53	  Py::module_ sys = Py::module_::import("sys");
    54	  sys.attr("path").attr("append")(TASK4_DIR);
    55	
    56	  // 添加 LLM 加持的 Pass 到优化管理器中
    57	  mpm.addPass(PassSequencePredict(
    58	    "<api_key>",
    59	    "<base_url>",
