    66	          mpm.addPass(StaticCallCounterPrinter(llvm::errs()));
    67	        } },
    68	      { "Mem2Reg",
    69	        TASK4_DIR "/Mem2Reg.hpp",
    70	        TASK4_DIR "/Mem2Reg.cpp",
    71	        "Mem2Reg.xml",
    72	        [](llvm::ModulePassManager& mpm) { mpm.addPass(Mem2Reg()); } },
    73	      { "ConstantFolding",
    74	        TASK4_DIR "/ConstantFolding.hpp",
    75	        TASK4_DIR "/ConstantFolding.cpp",
    76	        "ConstantFolding.xml",
    77	        [](llvm::ModulePassManager& mpm) {
    78	          mpm.addPass(ConstantFolding(llvm::errs()));
    79	        } },
    80	    }));
    81	
    82	#else
    83	
    84	  // 传统 LLVM Pass 来进行编译优化
    85	  // 添加优化pass到管理器中
    86	  mpm.addPass(StaticCallCounterPrinter(llvm::errs()));
    87	  mpm.addPass(Mem2Reg());
    88	  mpm.addPass(ConstantFolding(llvm::errs()));
    89	
    90	#endif
    91	
    92	  // 运行优化pass
    93	  mpm.run(mod, mam);
    94	}
